const input = $('When Executed by Another Workflow').first().json;

const topics = $input.all()
  .filter(item => item.json.id && item.json.title)
  .map(item => ({
    id: item.json.id,
    title: item.json.title
  }));

const messageType = input.message_type || 'text';

const parts = [];

if (input.content) {
  parts.push(`Content: ${input.content}`);
}

if (input.caption) {
  parts.push(`Caption: ${input.caption}`);
}

if (input.file_name) {
  parts.push(`File name: ${input.file_name}`);
}

if (input.mime_type) {
  parts.push(`MIME type: ${input.mime_type}`);
}

if (parts.length === 0) {
  parts.push(`Message type: ${messageType}`);
}

const messageForAI = parts.join('\n');

return [
  {
    json: {
      user_id: input.user_id,
      chat_id: input.chat_id,
      message_type: messageType,
      message_for_ai: messageForAI,
      topics
    }
  }
];

const original = $('prepare AI prompt').first().json;

// Try to read Gemini / LLM Chain output from common n8n fields
let raw =
  $json.text ||
  $json.output ||
  $json.response ||
  $json.message ||
  $json.content ||
  $json.chatInput ||
  '';

// Sometimes output can be an object
if (typeof raw !== 'string') {
  raw = JSON.stringify(raw);
}

// Remove possible markdown fences if Gemini returns ```json ... ```
raw = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let ai;

try {
  ai = JSON.parse(raw);
} catch (e) {
  ai = {
    action: 'create_new',
    suggested_topic_id: null,
    suggested_topic_title: null,
    new_topic_title: 'New Notes',
    confidence: 0,
    reason: 'I could not confidently classify this message.'
  };
}

const topics = original.topics || [];
const confidence = Number(ai.confidence || 0);
const action = ai.action;

function cleanTopicTitle(title) {
  return String(title || '')
    .replace(/[^\p{L}\p{N}\s&/-]/gu, '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 40);
}

// Case 1: AI suggests an existing topic
if (action === 'use_existing') {
  const topicId = ai.suggested_topic_id ? Number(ai.suggested_topic_id) : null;
  const matchedTopic = topics.find(t => Number(t.id) === topicId);

  if (topicId && matchedTopic && confidence >= 0.55) {
    const topicTitle = matchedTopic.title;
    const reason = ai.reason || 'This looks like the closest matching topic.';

    return [
      {
        json: {
          chat_id: original.chat_id,
          text:
`Suggested topic:

📁 ${topicTitle}

Reason: ${reason}`,
          inline_keyboard: [
            [
              {
                text: `✅ Save to ${topicTitle}`,
                callback_data: `select_topic:${topicId}`
              }
            ],
            [
              {
                text: '📁 Choose another topic',
                callback_data: 'action:choose_topic'
              }
            ],
            [
              {
                text: '➕ Create new topic',
                callback_data: 'action:create_new'
              }
            ]
          ]
        }
      }
    ];
  }
}

// Case 2: AI suggests a new topic
let newTopicTitle = cleanTopicTitle(ai.new_topic_title);

if (!newTopicTitle) {
  newTopicTitle = 'New Notes';
}

const reason = ai.reason || 'This would be a useful new topic for this message.';

return [
  {
    json: {
      chat_id: original.chat_id,
      text:
`Suggested new topic:

📁 ${newTopicTitle}

Reason: ${reason}

Create this topic and save the message here?`,
      inline_keyboard: [
        [
          {
            text: `✅ Create "${newTopicTitle}"`,
            callback_data: `ai_create_topic:${encodeURIComponent(newTopicTitle)}`
          }
        ],
        [
          {
            text: '📁 Choose existing topic',
            callback_data: 'action:choose_topic'
          }
        ],
        [
          {
            text: '➕ Create manually',
            callback_data: 'action:create_new'
          }
        ]
      ]
    }
  }
];
